1434→grouping_planner(PlannerInfo *root, double tuple_fraction,
  1435→				 SetOperationStmt *setops)
  1436→{
  1437→	Query	   *parse = root->parse;
  1438→	int64		offset_est = 0;
  1439→	int64		count_est = 0;
  1440→	double		limit_tuples = -1.0;
  1441→	bool		have_postponed_srfs = false;
  1442→	PathTarget *final_target;
  1443→	List	   *final_targets;
  1444→	List	   *final_targets_contain_srfs;
  1445→	bool		final_target_parallel_safe;
  1446→	RelOptInfo *current_rel;
  1447→	RelOptInfo *final_rel;
  1448→	FinalPathExtraData extra;
  1449→	ListCell   *lc;
  1450→
  1451→	/* Tweak caller-supplied tuple_fraction if have LIMIT/OFFSET */
  1452→	if (parse->limitCount || parse->limitOffset)
  1453→	{
  1454→		tuple_fraction = preprocess_limit(root, tuple_fraction,
  1455→										  &offset_est, &count_est);
  1456→
  1457→		/*
  1458→		 * If we have a known LIMIT, and don't have an unknown OFFSET, we can
  1459→		 * estimate the effects of using a bounded sort.
  1460→		 */
  1461→		if (count_est > 0 && offset_est >= 0)
  1462→			limit_tuples = (double) count_est + (double) offset_est;
  1463→	}
  1464→
  1465→	/* Make tuple_fraction accessible to lower-level routines */
  1466→	root->tuple_fraction = tuple_fraction;
  1467→
  1468→	if (parse->setOperations)
  1469→	{
  1470→		/*
  1471→		 * Construct Paths for set operations.  The results will not need any
  1472→		 * work except perhaps a top-level sort and/or LIMIT.  Note that any
  1473→		 * special work for recursive unions is the responsibility of
  1474→		 * plan_set_operations.
  1475→		 */
  1476→		current_rel = plan_set_operations(root);
  1477→
  1478→		/*
  1479→		 * We should not need to call preprocess_targetlist, since we must be
  1480→		 * in a SELECT query node.  Instead, use the processed_tlist returned
  1481→		 * by plan_set_operations (since this tells whether it returned any
  1482→		 * resjunk columns!), and transfer any sort key information from the
  1483→		 * original tlist.
  1484→		 */
  1485→		Assert(parse->commandType == CMD_SELECT);
  1486→
  1487→		/* for safety, copy processed_tlist instead of modifying in-place */
  1488→		root->processed_tlist =
  1489→			postprocess_setop_tlist(copyObject(root->processed_tlist),
  1490→									parse->targetList);
  1491→
  1492→		/* Also extract the PathTarget form of the setop result tlist */
  1493→		final_target = current_rel->cheapest_total_path->pathtarget;
  1494→
  1495→		/* And check whether it's parallel safe */
  1496→		final_target_parallel_safe =
  1497→			is_parallel_safe(root, (Node *) final_target->exprs);
  1498→
  1499→		/* The setop result tlist couldn't contain any SRFs */
  1500→		Assert(!parse->hasTargetSRFs);
  1501→		final_targets = final_targets_contain_srfs = NIL;
  1502→
  1503→		/*
  1504→		 * Can't handle FOR [KEY] UPDATE/SHARE here (parser should have
  1505→		 * checked already, but let's make sure).
  1506→		 */
  1507→		if (parse->rowMarks)
  1508→			ereport(ERROR,
  1509→					(errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
  1510→			/*------
  1511→			  translator: %s is a SQL row locking clause such as FOR UPDATE */
  1512→					 errmsg("%s is not allowed with UNION/INTERSECT/EXCEPT",
  1513→							LCS_asString(linitial_node(RowMarkClause,
  1514→													   parse->rowMarks)->strength))));
  1515→
  1516→		/*
  1517→		 * Calculate pathkeys that represent result ordering requirements
  1518→		 */
  1519→		Assert(parse->distinctClause == NIL);
  1520→		root->sort_pathkeys = make_pathkeys_for_sortclauses(root,
  1521→															parse->sortClause,
  1522→															root->processed_tlist);
  1523→	}
  1524→	else
  1525→	{
  1526→		/* No set operations, do regular planning */
  1527→		PathTarget *sort_input_target;
  1528→		List	   *sort_input_targets;
  1529→		List	   *sort_input_targets_contain_srfs;
  1530→		bool		sort_input_target_parallel_safe;
